create function docker_container_stop(id text, timeout int default null)
    returns void
as
$$
declare
    response omni_httpc.http_response;
begin
    select *
    into response
    from
        omni_httpc.http_execute_with_options(
                omni_httpc.http_execute_options(timeout => timeout, first_byte_timeout => timeout),
                omni_httpc.http_request(
                        format('http://%s/containers/%s/stop', omni_containers.docker_api_base_url(), id),
                        'POST'
                    )
            );
    case response.status
        when 204 then -- We're done
        return;
        when 304 then raise exception 'Can''t stop the container' using
            detail = 'Container already stopped';
        when 404 then raise exception 'Can''t stop the container' using
            detail = 'No such container';
        else raise exception 'Can''t stop the container: % (status % error: %)', convert_from(response.body, 'utf8'), response.status, response.error;
        end case;
end;
$$ language plpgsql;

create or replace function app.update_avatar_id()
    returns trigger
    language plpgsql
    security definer
    as $$
    declare
        v_handle app.valid_name;
        v_affected_account app.accounts := null;
    begin
        select (string_to_array(new.name, '/'::text))[1]::app.valid_name into v_handle;

        update app.accounts
        set avatar_id = new.id
        where handle = v_handle
        returning * into v_affected_account;

        if not v_affected_account is null then
            update auth.users u
            set
                "raw_user_meta_data" = u.raw_user_meta_data || jsonb_build_object(
                    'avatar_path', new.name
                )
            where u.id = v_affected_account.id;
        else
            update app.organizations
            set avatar_id = new.id
            where handle = v_handle;
        end if;

        return new;
    end;
    $$;

